import React, { useState, useEffect, useCallback, useRef } from 'react';
import axios from 'axios';
import Timer from './Timer';

const QuizPage = ({ quizId, teamInfo, onSubmit, onTimeout, onViolation }) => {
  const [questions, setQuestions] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [tabSwitchCount, setTabSwitchCount] = useState(0);
  const [submitting, setSubmitting] = useState(false);
  const [violationOccurred, setViolationOccurred] = useState(false);

  // Disable copy/paste/right-click
  useEffect(() => {
    const disableCopy = (e) => {
      e.preventDefault();
      return false;
    };

    const disableKeys = (e) => {
      if (
        (e.ctrlKey && (e.key === 'c' || e.key === 'v' || e.key === 'x' || e.key === 'a')) ||
        e.key === 'F12' ||
        (e.ctrlKey && e.shiftKey && e.key === 'I') ||
        (e.ctrlKey && e.key === 'u')
      ) {
        e.preventDefault();
        return false;
      }
    };

    document.addEventListener('contextmenu', disableCopy);
    document.addEventListener('copy', disableCopy);
    document.addEventListener('cut', disableCopy);
    document.addEventListener('paste', disableCopy);
    document.addEventListener('keydown', disableKeys);
    document.addEventListener('selectstart', disableCopy);

    return () => {
      document.removeEventListener('contextmenu', disableCopy);
      document.removeEventListener('copy', disableCopy);
      document.removeEventListener('cut', disableCopy);
      document.removeEventListener('paste', disableCopy);
      document.removeEventListener('keydown', disableKeys);
      document.removeEventListener('selectstart', disableCopy);
    };
  }, []);

  // Tab switching detection with auto-submit after 2 violations
  useEffect(() => {
    let warningShown = false;

    const handleVisibilityChange = () => {
      if (document.hidden && !submitting && !violationOccurred) {
        setTabSwitchCount(prev => {
          const newCount = prev + 1;

          // First violation - warning
          if (newCount === 1 && !warningShown) {
            warningShown = true;
            alert('Warning: Tab switching is not allowed. One more violation will end your quiz.');
          }

          // Second violation - auto submit
          if (newCount >= 2) {
            setViolationOccurred(true);
            alert('Quiz ended due to tab switching violation.');
            handleAutoSubmit();
          }

          return newCount;
        });
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('blur', handleVisibilityChange);

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('blur', handleVisibilityChange);
    };
  }, [submitting, violationOccurred]);

  // Prevent back navigation
  useEffect(() => {
    window.history.pushState(null, null, window.location.href);
    const handlePopState = () => {
      window.history.pushState(null, null, window.location.href);
      alert('Navigation is disabled during quiz');
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  // Fetch questions
  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        const response = await axios.get(`http://localhost:8000/questions/${quizId}`);
        setQuestions(response.data.questions);
      } catch (err) {
        setError('Failed to load questions');
      } finally {
        setLoading(false);
      }
    };
    fetchQuestions();
  }, [quizId]);

  const handleAutoSubmit = useCallback(async () => {
    if (submitting || Object.keys(answers).length === 0) return;

    setSubmitting(true);

    try {
      const answersList = Object.entries(answers).map(([qId, selected]) => ({
        question_id: parseInt(qId),
        selected_option: selected
      }));

      const response = await axios.post('http://localhost:8000/submit', {
        quiz_id: quizId,
        answers: answersList,
        tab_switch_count: tabSwitchCount
      });

      onSubmit({
        score: response.data.score,
        totalQuestions: response.data.total_questions,
        timeTaken: response.data.time_taken_microseconds
      });

    } catch (err) {
      console.error('Auto-submit failed:', err);
      window.location.reload();
    }
  }, [quizId, answers, tabSwitchCount, onSubmit, submitting]);

  const handleAnswerSelect = (questionId, option) => {
    if (submitting || violationOccurred) return;

    setAnswers(prev => ({
      ...prev,
      [questionId]: option
    }));

    // Auto move to next question
    if (currentIndex < questions.length - 1) {
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
      }, 200);
    }
  };

  const handleSubmit = async () => {
    if (submitting || violationOccurred) return;

    // Check if all questions answered
    if (Object.keys(answers).length !== questions.length) {
      alert(`Please answer all questions. (${Object.keys(answers).length}/${questions.length})`);
      return;
    }

    await handleAutoSubmit();
  };

  const handleTimeUp = () => {
    if (!submitting && !violationOccurred) {
      handleAutoSubmit();
      onTimeout();
    }
  };

  if (loading) {
    return (
      <div style={{ maxWidth: '600px', margin: '40px auto', textAlign: 'center', fontFamily: 'Arial' }}>
        Loading...
      </div>
    );
  }

  if (error || !questions.length) {
    return (
      <div style={{ maxWidth: '600px', margin: '40px auto', textAlign: 'center', fontFamily: 'Arial' }}>
        <p style={{ color: '#dc2626' }}>{error || 'No questions available'}</p>
        <button onClick={() => window.location.reload()} style={{ padding: '10px 20px', marginTop: '20px' }}>
          Retry
        </button>
      </div>
    );
  }

  const currentQuestion = questions[currentIndex];
  const answeredCount = Object.keys(answers).length;

  return (
    <div style={{
      maxWidth: '700px',
      margin: '20px auto',
      padding: '20px',
      backgroundColor: 'white',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif'
    }}>
      {/* Header */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '15px 0',
        borderBottom: '2px solid #f0f0f0',
        marginBottom: '30px'
      }}>
        <div>
          <span style={{ fontSize: '18px', fontWeight: '500', color: '#111' }}>
            Question {currentIndex + 1} of {questions.length}
          </span>
        </div>
        <Timer 
          initialSeconds={1800}
          onTimeUp={handleTimeUp}
          isActive={!submitting && !violationOccurred}
        />
      </div>

      {/* Warning Banner */}
      {tabSwitchCount > 0 && !violationOccurred && (
        <div style={{
          backgroundColor: '#fff3cd',
          color: '#856404',
          padding: '12px',
          marginBottom: '20px',
          fontSize: '14px',
          border: '1px solid #ffeeba',
          borderRadius: '4px'
        }}>
          ⚠️ Warning: Tab switching detected ({tabSwitchCount}/2). Next violation will end your quiz.
        </div>
      )}

      {violationOccurred && (
        <div style={{
          backgroundColor: '#f8d7da',
          color: '#721c24',
          padding: '12px',
          marginBottom: '20px',
          fontSize: '14px',
          border: '1px solid #f5c6cb',
          borderRadius: '4px'
        }}>
          ⚠️ Quiz ended due to policy violation. Submitting your answers...
        </div>
      )}

      {/* Question */}
      <div style={{ marginBottom: '30px' }}>
        <h2 style={{
          fontSize: '22px',
          fontWeight: '400',
          lineHeight: '1.5',
          color: '#111',
          marginBottom: '25px'
        }}>
          {currentQuestion.question}
        </h2>

        {/* Options */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          {currentQuestion.options.map((option, idx) => {
            const isSelected = answers[currentQuestion.id] === option;
            const optionLabel = String.fromCharCode(65 + idx);

            return (
              <div
                key={idx}
                onClick={() => !submitting && !violationOccurred && handleAnswerSelect(currentQuestion.id, option)}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  padding: '12px 15px',
                  backgroundColor: isSelected ? '#f0f7ff' : 'white',
                  border: `1px solid ${isSelected ? '#2563eb' : '#e5e7eb'}`,
                  borderRadius: '6px',
                  cursor: (submitting || violationOccurred) ? 'not-allowed' : 'pointer',
                  transition: 'all 0.2s',
                  opacity: (submitting || violationOccurred) ? 0.6 : 1
                }}
              >
                <span style={{
                  width: '24px',
                  height: '24px',
                  display: 'inline-flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  backgroundColor: isSelected ? '#2563eb' : 'white',
                  border: `1px solid ${isSelected ? '#2563eb' : '#d1d5db'}`,
                  borderRadius: '50%',
                  marginRight: '15px',
                  fontSize: '13px',
                  fontWeight: '500',
                  color: isSelected ? 'white' : '#4b5563'
                }}>
                  {optionLabel}
                </span>
                <span style={{
                  fontSize: '16px',
                  color: '#1f2937'
                }}>
                  {option}
                </span>
              </div>
            );
          })}
        </div>
      </div>

      {/* Footer */}
      <div style={{
        borderTop: '2px solid #f0f0f0',
        paddingTop: '20px',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center'
      }}>
        <span style={{ fontSize: '15px', color: '#4b5563' }}>
          Answered: {answeredCount}/{questions.length}
        </span>

        {answeredCount === questions.length && !submitting && !violationOccurred && (
          <button
            onClick={handleSubmit}
            style={{
              backgroundColor: '#2563eb',
              color: 'white',
              border: 'none',
              padding: '12px 32px',
              borderRadius: '6px',
              fontSize: '16px',
              fontWeight: '500',
              cursor: 'pointer',
              transition: 'background-color 0.2s'
            }}
            onMouseOver={(e) => e.target.style.backgroundColor = '#1d4ed8'}
            onMouseOut={(e) => e.target.style.backgroundColor = '#2563eb'}
          >
            Submit Quiz
          </button>
        )}

        {(submitting || violationOccurred) && (
          <span style={{ color: '#6b7280', fontSize: '15px' }}>
            {submitting ? 'Submitting...' : 'Violation - submitting...'}
          </span>
        )}
      </div>
    </div>
  );
};

export default QuizPage;
